import React, { useEffect, useState } from 'react';
import { fetchCurrentUser, fetchStoreCatalog, purchaseStoreItem } from '../utils/typingApi';
import '../styles/Marketplace.css';

export default function Marketplace() {
  const [catalog, setCatalog] = useState([]);
  const [currentUser, setCurrentUser] = useState(null);
  const [notice, setNotice] = useState('');

  const loadData = async () => {
    const [user, store] = await Promise.all([fetchCurrentUser(), fetchStoreCatalog()]);
    setCurrentUser(user);
    setCatalog(store.items || []);
  };

  useEffect(() => {
    loadData();
  }, []);

  const handlePurchase = async (itemId) => {
    try {
      const result = await purchaseStoreItem(itemId);
      setNotice(result.message || 'Purchase complete.');
      await loadData();
    } catch (error) {
      setNotice(error.message || 'Purchase failed.');
    }
  };

  return (
    <div className="marketplace-container">
      <div className="marketplace-header">
        <h1>Marketplace</h1>
        <p>Unlock skins, avatars, frames, and premium effects with wallet balance.</p>
        <div className="marketplace-balance">
          Wallet: KES {Number(currentUser?.balance || 0).toLocaleString()}
        </div>
      </div>

      {notice && <div className="marketplace-notice">{notice}</div>}

      <div className="marketplace-grid">
        {catalog.map((item) => (
          <div key={item.id} className="marketplace-card">
            <span className="marketplace-tag">{item.category}</span>
            <h3>{item.name}</h3>
            <p>{item.rarity} rarity unlock</p>
            <strong>KES {Number(item.price || 0).toLocaleString()}</strong>
            <button
              className={`btn ${item.owned ? 'btn-success' : 'btn-primary'}`}
              disabled={item.owned}
              onClick={() => handlePurchase(item.id)}
            >
              {item.owned ? 'Owned' : 'Buy Now'}
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}
